        partial void AfterOBPv510CreateUserWithAccountAccessById(ref bool suppressDefaultLog, IOBPv510CreateUserWithAccountAccessByIdApiResponse apiResponseLocalVar, string bankid, string accountid, string viewid, OBPv510CreateUserWithAccountAccessByIdRequest oBPv510CreateUserWithAccountAccessByIdRequest);

